```plantuml
@startuml
abstract class "Component" as Component {
    <<I>>
    + operation()
}

class "Decorator" as Decorator {
    <<A>>
    - component: Component
    + operation() ~ component.operation();
}

class "ConcreteComponent" as ConcreteComponent {
    <<C>>
    + operation()
}

class "ConcreteDecorateA" as ConcreteDecorateA {
    <<C>>
    - addState
    + operation()
}

class "ConcreteDecorateB" as ConcreteDecorateB {
    <<C>>
    + operation() ~ {super.operation(); addBehavior();}
    - addBehavior()
}

Component <|-- ConcreteComponent
Component <.. Decorator
Decorator *-- Component
Decorator <|-- ConcreteDecorateA
Decorator <|-- ConcreteDecorateB

@enduml
